INSERT INTO public.problem_statements
  (slug, title, description, how_to_start, domain, difficulty, organisation,
   source, source_event, official_url, dataset_links, resource_links, tags)
VALUES
  ('sih-chemicals-petrochem-idms', 'Real-Time Integrated Data Management for Chemicals and Petrochemicals', 'Build an International Comparative System that streams real-time data from the chemical and petrochemical sector into one integrated dashboard. The platform should compare Indian capacity, production and consumption against global benchmarks.', 'Start with the published statistics from the Department of Chemicals and Petrochemicals annual report and the OECD chemical production indices — convert each PDF table into CSVs you can ingest. Pick three or four large segments (polymers, organic chemicals, agro-chemicals, fertilizers) and model them in a Postgres schema with country, segment, capacity_mtpa, year columns. Use FastAPI for ingestion endpoints and Refine or Next.js for the dashboard so you can ship the comparative view in a weekend.

The hard part of this PS is keeping the data live. Wire a daily fetch job using GitHub Actions that pulls from public sources (CPMA, FICCI, ICIS where free) and writes deltas. Add anomaly flags when month-on-month change exceeds two sigma — judges reward this kind of operational thinking. Use Apache ECharts for time-series comparison.

Demo path — pre-load 2018-2023 data, then show a live ingest event that flips a country card from green to red. Make sure the export-to-PDF button works because policy users want briefing-paper output.', 'Govt', 'intermediate', 'Ministry of Chemicals and Fertilizers', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[{"label":"","url":"api: https://chemicals.gov.in"},{"label":"","url":"csv: https://data.gov.in"}]'::jsonb, '[{"label":"chemicals.gov.in/sites/default/files/Annual%20Report%202022-","url":"https://chemicals.gov.in/sites/default/files/Annual%20Report%202022-23.pdf","kind":"docs"},{"label":"echarts.apache.org/handbook/en/get-started","url":"https://echarts.apache.org/handbook/en/get-started","kind":"tutorial"}]'::jsonb, ARRAY['dashboard','petrochemicals','real-time','policy','comparative-analytics']::text[]),
  ('sih-differentiated-case-flow', 'Differentiated Case Flow Management for Court Listings', 'Develop software that streamlines the listing of cases in courts through Differentiated Case Flow Management — fast-tracking simple matters and routing complex ones to specialised benches. The output is a daily court board that respects judge availability, advocate conflicts and statutory time-limits.', 'Read the High Court of Delhi DCM Rules 2018 first — they define five tracks based on case complexity. Build a synthetic dataset of 2,000 cases with tags (cognizable, civil-money, family, writ) and code a rule engine in Python that scores each case for track assignment. Use OR-Tools CP-SAT to solve the daily allocation as a constraint problem — judge bandwidth, courtroom capacity, advocate calendar.

Front-end matters here because registrars are the actual users. Build a Next.js board with drag-to-reschedule, conflict warnings inline, and a read-only mobile view for advocates. Hook in a Twilio-style SMS stub so litigants get the listing date.

Win condition — show that simple-track cases get disposed in under 90 days in your simulated docket while complex track keeps its review cadence. Print a one-page PDF of the cause list per day.', 'Govt', 'advanced', 'Ministry of Law and Justice', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"main.sci.gov.in/pdf/AnnualReports/Annual_Report_2021-22.pdf","url":"https://main.sci.gov.in/pdf/AnnualReports/Annual_Report_2021-22.pdf","kind":"docs"},{"label":"github.com/google/or-tools","url":"https://github.com/google/or-tools","kind":"repo"}]'::jsonb, ARRAY['legal-tech','scheduling','or-tools','court-listing','constraint-solving']::text[]),
  ('sih-childrens-rights-gamified', 'Gamified Children Rights Legal Literacy Platform', 'Design a gamified web/app platform that teaches Indian school children about their legal rights under POCSO, JJ Act and the Constitution. Progression, badges and quizzes should make legal concepts age-appropriate across grades 5-12.', 'Start with the NCPCR childline curriculum PDFs and break each right into a quest — Safe Touch, Right to Education, Speak Up. Use Phaser.js or Godot for the mini-games and React for the parent-teacher dashboard. Keep payload tiny because the target schools have slow internet — every level should be under 500KB.

The pedagogy is what wins judges. Pair each game with a 60-second animation explainer (use LottieFiles), and gate level progression behind a five-question quiz. Add a teacher mode that exports a class report as CSV.

Demo with a real student walk-through — record a 7-year-old playing two levels. Localise to Hindi and one regional language so judges see scale-out potential. Open-source under MIT so the Ministry can adopt without licensing friction.', 'Education', 'intermediate', 'Ministry of Law and Justice', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"ncpcr.gov.in/","url":"https://ncpcr.gov.in/","kind":"docs"},{"label":"phaser.io/learn","url":"https://phaser.io/learn","kind":"tutorial"}]'::jsonb, ARRAY['gamification','legal-literacy','edtech','children-rights','phaser']::text[]),
  ('sih-undertrial-prisoners-tech', 'Tech-Driven Case Tracking for Undertrial Prisoners', 'Build a system that surfaces undertrial prisoners eligible for bail under Section 436A CrPC — i.e. those who have spent more than half their maximum possible sentence in custody without trial completion. The tool should connect e-Prisons data with court calendars to flag pending cases.', 'Start with the National Prisons Information Portal data structure (e-Prisons MIS) and the eCourts National Judicial Data Grid API. Mock both with sample JSON, then build a Python ETL that joins prisoner records with case status — the join key is FIR number and CNR number. Apply the 436A logic as a SQL view that returns flagged inmates with days_overdue.

Design a Legal Aid Cell dashboard in Streamlit or Next.js — case file, days in custody, next hearing date, contact for District Legal Services Authority. Add a one-click PDF petition draft using a Jinja template so paralegals can file mercy applications instantly.

The demo that wins this is impact arithmetic — show that out of 10,000 synthetic prisoners, your tool surfaces the 380 who qualify under 436A and generates ready petitions. Cite NALSA reports for context.', 'Govt', 'advanced', 'Ministry of Law and Justice', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"eprisons.nic.in/","url":"https://eprisons.nic.in/","kind":"docs"},{"label":"ecourts.gov.in/ecourts_home/","url":"https://ecourts.gov.in/ecourts_home/","kind":"docs"}]'::jsonb, ARRAY['prison-tech','section-436a','legal-aid','e-prisons','ecourts']::text[]),
  ('sih-water-footprint-calculator', 'Digital Water Footprint Calculator for Daily Items', 'Develop a digital tool that calculates the water footprint of everyday consumer items — a cotton t-shirt, a cup of coffee, a kilogram of paneer. The output guides users toward lower-water lifestyle choices and supports the Jal Shakti mission.', 'Use the Water Footprint Network methodology — green, blue and grey water for each product. Their public dataset has values for 200+ crops and goods; import as a JSON lookup table. Build a Flutter app with a barcode scanner that hits the OpenFoodFacts API, then maps category to footprint estimate.

The insight layer is what differentiates this. Show a daily water budget meter, alternative suggestions (almond milk to soy milk saves ~80 percent water), and a household-level tally that rolls up to a monthly report. Use Riverpod for state and Firestore as the lightweight backend.

For the demo, scan five real grocery items and show the cumulative footprint exceeding a typical household allocation — narrative beats numbers in judging. Add a share card that gamifies water savings on WhatsApp.', 'AI/ML', 'beginner', 'Ministry of Jal Shakti', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[{"label":"","url":"api: https://world.openfoodfacts.org/data"}]'::jsonb, '[{"label":"www.waterfootprint.org/en/water-footprint/product-water-foot","url":"https://www.waterfootprint.org/en/water-footprint/product-water-footprint/","kind":"docs"},{"label":"flutter.dev/docs","url":"https://flutter.dev/docs","kind":"tutorial"}]'::jsonb, ARRAY['water-footprint','flutter','sustainability','consumer-tech','barcode']::text[]),
  ('sih-non-revenue-water-digital', 'Digital Approach to Reducing Non-Revenue Water', 'Tackle Non-Revenue Water (NRW) — water that is treated and distributed but never billed due to leaks, theft or metering errors. Build a digital system that ingests SCADA flow data, identifies leak signatures and quantifies NRW district-wise.', 'Read the AWWA M36 manual on water audits to internalise the water-balance equation. Spin up InfluxDB locally and stream simulated DMA (District Metered Area) inflow and outflow at 15-minute resolution. Use Pandas to compute minimum night flow per DMA — sustained high MNF is the canonical leak signature.

Layer ML on top — an Isolation Forest detects unusual patterns and a small XGBoost regressor estimates leak volume from pressure-flow signatures. Grafana for the operator dashboard, and a Mapbox overlay coloured by NRW percentage per DMA.

The winning move is a Pareto chart that ranks DMAs by potential litres-recovered-per-rupee-of-repair. Utility heads care about ROI not models. Wrap the whole thing in Docker Compose so it deploys to any state Jal Board cluster.', 'IoT', 'advanced', 'Ministry of Jal Shakti', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"www.awwa.org/Resources-Tools/Resource-Topics/Water-Loss-Cont","url":"https://www.awwa.org/Resources-Tools/Resource-Topics/Water-Loss-Control","kind":"docs"},{"label":"github.com/influxdata/influxdb","url":"https://github.com/influxdata/influxdb","kind":"repo"}]'::jsonb, ARRAY['nrw','scada','leak-detection','water-utility','isolation-forest']::text[]),
  ('sih-flood-inundation-projection', 'Projecting Flood Inundation Extent from River Level Forecasts', 'Project the spatial extent of flood inundation that corresponds to forecast river levels at gauging stations. Output is a polygon layer of likely submerged area for next 24/48/72 hours that disaster managers can overlay on settlements.', 'Pull a DEM (SRTM 30m or Bhuvan Cartosat 30m) of a single river reach — the Kosi or Mahanadi work well. Use HEC-RAS 2D or the open-source LISFLOOD-FP to run flood simulations for ten discrete stage-heights and store the resulting inundation polygons as GeoJSON. That is your offline lookup table.

For live operation, take CWC forecast bulletins, parse the stage forecast and interpolate between your pre-run polygons. Render on a Leaflet or Mapbox map with three timestep layers. Add a settlement-impact panel that intersects polygons with Bhuvan village boundaries.

Demo with the 2008 Kosi event as a historical replay — show your tool would have flagged 220 villages 48 hours before the breach. Always cite CWC and ISRO Bhuvan as data sources — judges check provenance.', 'AI/ML', 'advanced', 'Ministry of Jal Shakti', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[{"label":"","url":"api: https://bhuvan.nrsc.gov.in"},{"label":"","url":"csv: https://cwc.gov.in"}]'::jsonb, '[{"label":"www.hec.usace.army.mil/software/hec-ras/","url":"https://www.hec.usace.army.mil/software/hec-ras/","kind":"docs"},{"label":"github.com/openhydrology/lisflood-fp","url":"https://github.com/openhydrology/lisflood-fp","kind":"repo"}]'::jsonb, ARRAY['flood-modeling','hec-ras','gis','disaster','hydrology']::text[]),
  ('sih-namami-gange-chatbot-mascot', 'Chacha Chaudhary River Mascot Chatbot', 'Build an AI-powered conversational mascot — branded as Chacha Chaudhary for Namami Gange — that engages citizens on river conservation, answers questions about Ganga ecology and nudges behaviour change.', 'Curate a corpus from the National Mission for Clean Ganga FAQ documents, NMCG annual reports and the Namami Gange progress dashboards. Index it in a vector store (Qdrant or pgvector) and front it with a retrieval-augmented LLM — Gemini Flash or Llama 3 Instruct works at zero/low cost.

Give the bot personality. Chacha Chaudhary is a beloved Pran character — license-aware, use a stylised non-IP-violating avatar (or get NMCG permission). Implement a Rasa or LangChain conversation loop with three modes — Learn, Quiz, Pledge. Web-app first (Next.js), then wrap as Telegram bot.

The wow factor is voice — add Sarvam AI or Bhashini for Hindi/Bhojpuri/Bengali so a Ganga-side villager can talk to the bot. End each session with a one-tap pledge to reduce plastic use, log it to a dashboard NMCG can show as engagement KPI.', 'AI/ML', 'intermediate', 'Ministry of Jal Shakti', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"nmcg.nic.in/","url":"https://nmcg.nic.in/","kind":"docs"},{"label":"www.bhashini.gov.in/","url":"https://www.bhashini.gov.in/","kind":"docs"}]'::jsonb, ARRAY['chatbot','rag','namami-gange','bhashini','behaviour-change']::text[]),
  ('sih-hydro-plant-generative-design', 'AI-Based Generative Design of Hydro Power Plants', 'Use generative design and AI to propose optimal layouts for small and medium hydro power plants given site DEM, river discharge profile and land constraints. Reduce design cycle from months to days.', 'Start with the CWC small hydro design handbook to learn the variables — head, discharge, turbine type, penstock diameter, powerhouse footprint. Code these as a parametric model in Grasshopper for Rhino, or do it programmatically with Autodesk Fusion 360 API since Autodesk was a SIH 2023 sponsor.

Wrap the parametrics in an evolutionary loop — NSGA-II in Pymoo for multi-objective optimisation (max power output, min land take, min cost). Train a small surrogate XGBoost so each candidate evaluation is sub-second rather than running full CFD.

The demo is a single command — given a site GeoTIFF, output the top-5 plant layouts as STEP files with capacity, LCOE and land-take printed. Use the SHP6 small hydro project DPRs from MNRE as ground truth for validation.', 'AI/ML', 'advanced', 'Ministry of Power', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"mnre.gov.in/small-hydro/","url":"https://mnre.gov.in/small-hydro/","kind":"docs"},{"label":"github.com/anyoptimization/pymoo","url":"https://github.com/anyoptimization/pymoo","kind":"repo"}]'::jsonb, ARRAY['generative-design','hydropower','nsga-ii','fusion-360','renewables']::text[]),
  ('sih-grid-microgrid-cyber-controller', 'Cybersecurity-Enabled Smart Controller for Grid-Connected Microgrid', 'Design a cybersecurity-hardened smart controller for grid-connected microgrids. The controller must handle islanding, resynchronisation and reverse power flow while resisting common SCADA cyberattacks like Modbus replay and false data injection.', 'Get an ESP32 or a Raspberry Pi with a CAN-bus hat, then build a small simulated microgrid in OpenDSS or pandapower with a 50 kW PV array and a battery. The controller exposes Modbus-TCP for SCADA. Implement role-based access, TLS on Modbus (using libmbus-tls), and HMAC on all setpoint writes.

Build the attacker side too — a Python script that sniffs and replays Modbus packets. Show that without your hardening the attacker can trip the islanding relay; with your hardening, every replay is logged and refused. This binary demonstration is what judges remember.

Add a small ML anomaly detector (autoencoder on Modbus traffic) so unknown attack patterns also get flagged. Cite IEC 62351 throughout for compliance credibility.', 'IoT', 'advanced', 'Ministry of Power', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"webstore.iec.ch/publication/6912","url":"https://webstore.iec.ch/publication/6912","kind":"docs"},{"label":"github.com/sourceperl/pyModbusTCP","url":"https://github.com/sourceperl/pyModbusTCP","kind":"repo"}]'::jsonb, ARRAY['microgrid','modbus','scada-security','iec-62351','esp32']::text[]),
  ('sih-cognitive-retraining-disabilities', 'Computerized Cognitive Retraining for Children with Disabilities', 'Develop a home-training cognitive retraining program for children with intellectual or developmental disabilities. Adaptive exercises target attention, memory, problem-solving and social cognition with parent-led delivery.', 'Talk to a special educator first — even a 30-minute call shapes the design. Then read the NIMH Secunderabad cognitive retraining manual (open access). Map each cognitive domain to a mini-game: visual attention as a find-the-symbol task, working memory as a card-flip game, executive function as a Stroop variant.

Build in Unity or Godot for offline-first deployment so rural homes without internet can use it. Tablet-friendly, large touch targets, voice prompts in Hindi/Tamil/Marathi. Track every interaction locally and sync to a clinician dashboard when WiFi appears.

The killer feature is adaptive difficulty — use a simple Elo-style rating so the task gets harder only when the child gets three in a row. Add a parent guide PDF that explains what each task trains and how to praise effort. Pilot data from even five children, recorded as testimonials, is worth more than any benchmark.', 'Health', 'intermediate', 'Ministry of Social Justice and Empowerment', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"nimhindia.gov.in/","url":"https://nimhindia.gov.in/","kind":"docs"},{"label":"learn.unity.com/","url":"https://learn.unity.com/","kind":"tutorial"}]'::jsonb, ARRAY['cognitive-retraining','special-education','unity','accessibility','adaptive']::text[]),
  ('sih-oil-gas-explosion-zone', 'Threat Zone Modeling for Oil and Gas Explosions', 'Model the threat zone of an explosion — toxic vapour cloud, overpressure, thermal radiation — in oil and gas handling facilities. The output is a real-time hazard map that disaster response teams use during incidents.', 'Install ALOHA from US EPA (free) and learn the three threat models — toxic, flammable, BLEVE/fireball. Recreate the Jaipur IOCL 2009 fire as a sanity-check case. Then write a Python wrapper that calls ALOHA-style equations directly (Gaussian dispersion, TNO multi-energy method) so you do not depend on the GUI.

Wrap it in a FastAPI service that accepts substance, release-rate, wind-speed, atmospheric stability and returns three concentric polygons (red-orange-yellow). Render on Leaflet with the refinery as the center. Connect to a wind-data feed from IMD or OpenWeather every 5 minutes.

For judging, show two scenarios — a propane leak with downwind vapour cloud and an LPG BLEVE with thermal radiation rings. Overlay on a synthetic township map with shelter-in-place vs evacuation zones tagged. Cite OISD and PESO guidelines.', 'AI/ML', 'advanced', 'Ministry of Home Affairs', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"www.epa.gov/cameo/aloha-software","url":"https://www.epa.gov/cameo/aloha-software","kind":"docs"},{"label":"www.oisd.gov.in/","url":"https://www.oisd.gov.in/","kind":"docs"}]'::jsonb, ARRAY['explosion-modeling','aloha','industrial-safety','dispersion','hazmat']::text[]),
  ('sih-wool-farm-to-fabric', 'Wool Traceability from Farm to Fabric', 'Build an application that traces wool from the sheep farm through scouring, carding, spinning, weaving and final fabric. Each batch carries a tamper-evident provenance record so handloom buyers can verify origin and quality.', 'Read the Central Wool Development Board handbook to understand the value chain — Pashmina, Marwari, Deccani, Magra varieties differ enormously in micron count and shrinkage. Model each transformation step as a state machine: raw fleece, scoured, carded, yarn, fabric — each transition adds attributes (micron, twist, gsm).

Use Hyperledger Fabric or a simpler Merkle-tree log on Postgres for the chain-of-custody. Generate QR codes at each step; the buyer scans the final bolt and sees the full lineage. Build a Flutter app for farmers (offline-first, capture photos and weights) and a React dashboard for the wool board.

The market hook is GI tagging — Pashmina with verifiable Ladakh origin sells at 3x. Show this delta in the demo with a side-by-side price comparison. Tie weight-loss-during-scouring as an objective quality metric (Pashmina yields drop is 40-50 percent).', 'AI/ML', 'intermediate', 'Ministry of Textiles', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"woolboard.nic.in/","url":"https://woolboard.nic.in/","kind":"docs"},{"label":"hyperledger-fabric.readthedocs.io/","url":"https://hyperledger-fabric.readthedocs.io/","kind":"docs"}]'::jsonb, ARRAY['wool','traceability','supply-chain','hyperledger','handloom']::text[]),
  ('sih-dredging-decision-support', 'Dredging Analysis and Decision Support System', 'Decision support tool for port dredging — analyse bathymetry data, predict sedimentation rates and recommend dredging schedules and disposal sites to maintain channel depth at minimum cost.', 'Grab Survey of India bathymetric charts for one port (Paradip works well) and discharge data from CWC for the feeder rivers. Build a sedimentation model — a simplified Krone-Partheniades formula for cohesive sediment plus a Van Rijn formula for non-cohesive. Validate against the port authority published dredging-volumes for last five years.

Wrap it in a Streamlit dashboard with three views — current bathymetry heatmap, predicted siltation in 30/60/90 days, and a recommended dredger deployment plan. Use OR-Tools to optimise schedule across multiple trailing-suction-hopper dredgers given capacity, transit time to dump site and weather windows.

Dredging is fuel-intensive — every cubic-metre saved is INR 200 saved. Make the front-page KPI rupees-saved-per-year. Add a dispute mode that shows when contractor invoiced quantities exceed model predictions.', 'AI/ML', 'advanced', 'Ministry of Ports, Shipping and Waterways', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"shipmin.gov.in/","url":"https://shipmin.gov.in/","kind":"docs"},{"label":"www.sciencedirect.com/science/article/pii/S0378383900000314","url":"https://www.sciencedirect.com/science/article/pii/S0378383900000314","kind":"paper"}]'::jsonb, ARRAY['dredging','bathymetry','ports','sedimentation','or-tools']::text[]),
  ('sih-mining-acts-chatbot', 'Chatbot for Mining Acts Rules and Regulations', 'Conversational chatbot that answers natural-language queries on the Mines Act 1952, MMDR Act 1957, Mineral Concession Rules and state-level mining regulations. Targets mine operators, inspectors and policy researchers.', 'Download every Act and Rule from the Ministry of Coal and Ministry of Mines websites (each is a PDF). Chunk them at section-level with the section number preserved as metadata. Embed using bge-small or e5-small (open-source) and store in pgvector. Front with a Llama 3 8B or Gemini Flash retrieval chain.

The correctness bar is high — citing the wrong section gets a mine fined. Every answer must include the section reference and a copy-pasteable quote. Build a feedback loop where inspectors mark answers as accurate or not, and use that to improve retrieval weights.

Add a What-If mode — paste a scenario (overburden ratio 1:8, lease under MMDR) and the bot returns applicable rules and penalty schedule. Demo with three real DGMS bulletins as test cases.', 'AI/ML', 'intermediate', 'Ministry of Coal', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"coal.nic.in/","url":"https://coal.nic.in/","kind":"docs"},{"label":"mines.gov.in/","url":"https://mines.gov.in/","kind":"docs"}]'::jsonb, ARRAY['legal-chatbot','rag','mining-law','pgvector','compliance']::text[]),
  ('sih-shovel-dumper-load-status', 'Real-Time Dumper Load Status for Shovel Operator', 'Provide the shovel operator with real-time visibility of dumper load status — current weight, fill percentage and remaining capacity — so loading cycles are optimised and overloads avoided.', 'On an open-pit truck a strain-gauge load cell on each suspension strut gives axle weight; sum them for gross weight. For mock-up, use four HX711 modules with 50kg load cells on a model truck. ESP32 reads, calculates fill percentage, broadcasts over LoRa to the shovel cab display.

The shovel-cab display is what wins the use case — a 7-inch screen showing current truck identity (RFID), current weight, target weight and a colour bar. Add a haptic buzz when target is reached so the operator does not have to keep eyes on the screen.

Real coal mines use OEM-locked systems — Komatsu or Caterpillar pricing is INR 10 lakh per truck. Pitch yours at INR 50,000 with open hardware. Add a fleet dashboard in Grafana showing average overload and cycle time per shift.', 'IoT', 'intermediate', 'Ministry of Coal', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"www.coalindia.in/","url":"https://www.coalindia.in/","kind":"docs"},{"label":"randomnerdtutorials.com/esp32-load-cell-hx711/","url":"https://randomnerdtutorials.com/esp32-load-cell-hx711/","kind":"tutorial"}]'::jsonb, ARRAY['mining-iot','load-cell','lora','shovel-dumper','esp32']::text[]),
  ('sih-glis-land-analytics', 'Analytics on Govt Land Information System Data', 'Build analytics on the Government Land Information System (GLIS) — the consolidated registry of central-government land holdings. Detect encroachments, idle parcels and high-value monetisation candidates.', 'GLIS data is published as state-wise CSVs by Department of Public Enterprises. Ingest into Postgres with PostGIS, geocode the parcels (some only have khasra numbers — chain through CCLA records). Cross-reference with Bhuvan land-use to flag mismatch — e.g. industrial parcel showing as agriculture from above.

Layer two analytics — idle-detection (no activity signature in satellite imagery over 3 years) and monetisation-score (circle-rate, road-frontage, FSI). Use Sentinel-2 NDVI time series via Google Earth Engine for the activity check.

Wrap in a Mapbox dashboard with a parcel inspector panel showing all attributes plus a download-as-PDF button. Demo with three handpicked parcels — one encroached, one idle, one ripe for monetisation. Always cite GLIS as source.', 'AI/ML', 'advanced', 'Ministry of Coal', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[{"label":"","url":"api: https://glis.dolr.gov.in"},{"label":"","url":"csv: https://data.gov.in"}]'::jsonb, '[{"label":"glis.dolr.gov.in/","url":"https://glis.dolr.gov.in/","kind":"docs"},{"label":"earthengine.google.com/","url":"https://earthengine.google.com/","kind":"tutorial"}]'::jsonb, ARRAY['glis','land-records','postgis','satellite','monetisation']::text[]),
  ('sih-domestic-waste-kerala', 'Domestic Waste Management Tracking and Routing', 'Digital platform for Kerala domestic waste management — citizens schedule pickups, ward-level segregation tracking, route optimisation for waste collection vehicles and ULB-level analytics.', 'Start with the Kerala Suchitwa Mission decentralised model — biodegradable waste is composted at household level, only non-biodegradable goes to collection points. Model the flow as three streams (compostable, recyclable, residual) with separate workflows.

Flutter app for citizens with QR-coded pickup slips, and a driver app with a TSP solver (use OR-Tools VRP) that takes ward boundaries and produces a daily route. Backend on Supabase. Push notifications when truck is 10 minutes away so citizens can place bins out.

The ULB dashboard is the differentiator — segregation compliance per ward, vehicle utilisation, fuel cost per tonne. Add a citizen-grievance channel that geotags illegal dump sites. Demo with Kochi corporation data publicly available on Sanitation Mission portal.', 'Govt', 'intermediate', 'Government of Kerala', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"sanitation.kerala.gov.in/","url":"https://sanitation.kerala.gov.in/","kind":"docs"},{"label":"github.com/google/or-tools","url":"https://github.com/google/or-tools","kind":"repo"}]'::jsonb, ARRAY['waste-management','route-optimisation','kerala','vrp','ulb']::text[]),
  ('sih-rural-telemedicine-kiosk', 'AI-Assisted Tele-Medicine KIOSK for Rural India', 'Tele-medicine KIOSK with on-board diagnostics (BP, SpO2, ECG, weight) plus an AI triage layer that helps the operator (ASHA worker) decide if the patient needs immediate tele-consult, scheduled visit or self-care.', 'List the cheapest reliable devices first — Omron HEM-7120 (BP, INR 1,800), Mi pulse oximeter (INR 1,200), AliveCor KardiaMobile (ECG, INR 5,000). All have BLE; build a Flutter app that connects to all three sequentially and stores readings in a FHIR-compatible JSON.

The AI layer is a decision tree — not a fancy model. NICE chest-pain guidelines, hypertension classification, hypoxia threshold — these are codified. Use a rule engine that explains why each tier (red/amber/green) was assigned. Integrate with eSanjeevani for the actual video consult.

For judges, do a live patient walk-through. The ASHA worker is your real user — design for two-finger typing and limited literacy. Add voice prompts in regional language. Cite NHA-FHIR profiles so it slots into ABDM.', 'Health', 'intermediate', 'Government of Kerala', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"www.esanjeevani.in/","url":"https://www.esanjeevani.in/","kind":"docs"},{"label":"abdm.gov.in/","url":"https://abdm.gov.in/","kind":"docs"}]'::jsonb, ARRAY['telemedicine','rural-health','fhir','esanjeevani','asha']::text[]),
  ('sih-text-to-video-pib-multilingual', 'Text-to-Video for PIB Press Releases in 13 Indian Languages', 'Convert Press Information Bureau press releases into auto-generated videos in English plus 13 regional languages using AI, GANs or diffusion video models. Each video has matching voiceover, captions and brand-consistent visuals.', 'Pipeline is four stages — summarise (Llama 3 to a 60-second script), TTS (Bhashini or Coqui XTTS for 13 languages), visuals (Stable Video Diffusion or stock B-roll matched by CLIP), and assembly (FFmpeg). Each stage isolated so you can swap providers without breaking others.

Get 100 actual PIB press releases from pib.gov.in. For each, generate a video and run a human eval — does the visual match the news, is the TTS pronouncing minister names correctly, is the caption synced. Pronunciation of Indian names is where most pipelines fail; build a name dictionary as an override.

The production realism is everything. Add PIB watermark, government colour palette, a 5-second intro template. Demo with three press releases across three languages, side-by-side comparison with English original. Open-source the name dictionary as a deliverable in its own right.', 'AI/ML', 'advanced', 'Ministry of Information and Broadcasting', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"www.bhashini.gov.in/","url":"https://www.bhashini.gov.in/","kind":"docs"},{"label":"github.com/coqui-ai/TTS","url":"https://github.com/coqui-ai/TTS","kind":"repo"}]'::jsonb, ARRAY['text-to-video','bhashini','tts','multilingual','pib']::text[]),
  ('sih-news-feedback-360', '360-Degree Feedback Software for Government News in Regional Media', 'Aggregate and analyse how government schemes are covered across regional-language newspapers, TV channels and social media. AI/ML produces a 360-degree sentiment scorecard so policy teams know which schemes are landing.', 'Set up scrapers for ten regional newspapers (Eenadu, Mathrubhumi, Anandabazar, Loksatta etc) using Playwright with respectful crawl-delays. Translate to English using IndicTrans2, then run sentiment with a fine-tuned IndicBERT model — Hindi/Tamil/Bengali sentiment is materially different from English sentiment.

Build a scheme-tagger that detects mentions of PMAY, Ayushman Bharat, PM-Kisan etc using NER plus regex. Aggregate to a daily heatmap — scheme on X-axis, state on Y, colour intensity for sentiment. Click to drill into actual article snippets.

The political-economy aware feature — track sentiment delta after announcements. If Ayushman Bharat sentiment dips in Bihar after a price-cap notification, the dashboard surfaces it within 24 hours. Cite each article URL so analysts can verify quickly.', 'AI/ML', 'advanced', 'Ministry of Information and Broadcasting', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"ai4bharat.iitm.ac.in/indic-trans2/","url":"https://ai4bharat.iitm.ac.in/indic-trans2/","kind":"docs"},{"label":"github.com/AI4Bharat/IndicBERTv2","url":"https://github.com/AI4Bharat/IndicBERTv2","kind":"repo"}]'::jsonb, ARRAY['media-monitoring','sentiment','regional-language','indictrans','policy']::text[]),
  ('sih-tor-de-anonymisation-crypto', 'De-anonymisation for Tracking Illegal Crypto Activity', 'Build techniques to de-anonymise actors performing illegal activity through cryptocurrency transactions — heuristics to cluster wallets, identify exchange off-ramps and trace mixer hops on Bitcoin and Ethereum.', 'Pull the Bitcoin blockchain via a Bitcoin Core full node or use BlockSci for historical analysis. Implement the three canonical clustering heuristics — multi-input, change-address detection and behavioural (Meiklejohn 2013). Validate on the WalletExplorer ground-truth labels.

Layer mixer detection — Wasabi, Samourai and Tornado Cash on Ethereum have known deposit-pool addresses. Flag any inbound funds from these as high-risk. For Ethereum, use The Graph or Etherscan API for token transfers.

The presentation matters more than the model. Build a Maltego-style graph visualiser in Sigma.js where each node is a wallet and edges are transactions. Demo by tracing a real ransomware payment from a public BleepingComputer report to a Binance off-ramp address.', 'Web3', 'advanced', 'National Technical Research Organisation', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"cseweb.ucsd.edu/~smeiklejohn/files/imc13.pdf","url":"https://cseweb.ucsd.edu/~smeiklejohn/files/imc13.pdf","kind":"paper"},{"label":"github.com/citp/BlockSci","url":"https://github.com/citp/BlockSci","kind":"repo"}]'::jsonb, ARRAY['blockchain-forensics','deanonymisation','wallet-clustering','mixer-detection','ntro']::text[]),
  ('sih-ubuntu-hardening-gui', 'GUI-Based Ubuntu Hardening Script for Org Policies', 'Build a GUI tool that hardens Ubuntu boxes per organisational security policies — STIG, CIS benchmarks or custom playbooks. Admins toggle controls visually, the tool applies and produces an audit report.', 'Start with the CIS Ubuntu 22.04 benchmark PDF — 200+ controls grouped into categories. Map each control to a shell command or systemd setting. The atomic unit is a Python class with check(), apply() and revert() methods.

GUI in PyQt6 or Tauri+React — tree view of controls with checkboxes, severity icons, and a real-time output console. Every action writes to /var/log/yourtool.audit so a reviewer can replay it. Provide a dry-run mode that just reports compliance without applying.

For the demo, take a vanilla 22.04 VM, run a baseline OpenSCAP scan (40 percent compliant), apply your hardening, rerun (96 percent compliant). That delta visualised is the strongest pitch. Ship as a .deb and as a one-line curl install.', 'Govt', 'intermediate', 'National Technical Research Organisation', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"www.cisecurity.org/benchmark/ubuntu_linux","url":"https://www.cisecurity.org/benchmark/ubuntu_linux","kind":"docs"},{"label":"github.com/OpenSCAP/openscap","url":"https://github.com/OpenSCAP/openscap","kind":"repo"}]'::jsonb, ARRAY['linux-hardening','cis-benchmark','compliance','pyqt','audit']::text[]),
  ('sih-fec-scheme-identification', 'Identifying Forward Error Correction Schemes in Unknown Signals', 'Identify and extract the Forward Error Correction (FEC) scheme used in unknown demodulated signals — convolutional, Reed-Solomon, LDPC, Turbo — given only the bit stream. Useful for SDR-based signal intelligence.', 'Capture sample I/Q streams from GNU Radio with known FEC encoders (gr-fec has all the standard ones). Demodulate to bits, then build a classifier on statistical features — autocorrelation at common code-rates (1/2, 1/3, 3/4, 7/8), syndrome distribution, dual-code analysis (Marazin 2009 paper is the canonical reference).

Layer ML on top — a 1D-CNN that takes a 1,024-bit sliding window and predicts code family. Train on a synthetic dataset of 20 known FEC schemes. For convolutional, additionally recover the polynomial generators using the Cluzeau algorithm.

Integrate as a GNU Radio block that auto-detects FEC and chains into the appropriate decoder. Demo over the air with an RTL-SDR receiving a known signal where the user does not know the FEC — your tool identifies it and the decoder unlocks the payload. Cite Marazin and Cluzeau throughout.', 'AI/ML', 'advanced', 'National Technical Research Organisation', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"www.gnuradio.org/","url":"https://www.gnuradio.org/","kind":"docs"},{"label":"hal.science/hal-00444604","url":"https://hal.science/hal-00444604","kind":"paper"}]'::jsonb, ARRAY['fec','sdr','signal-intelligence','gnu-radio','convolutional-code']::text[]),
  ('sih-network-compromise-non-ioc', 'AI Detection of Network Compromise Beyond IoCs', 'Detect whether a system, firewall, router or network is compromised using AI/ML — without relying only on Indicators of Compromise. The model must catch zero-day and living-off-the-land attacks via behavioural patterns.', 'Use the CICIDS 2017 and UNSW-NB15 public datasets, plus the more recent CIC-IoT-2023. Build flow-level features with CICFlowMeter. Train two models — an autoencoder for unsupervised anomaly detection and a HistGradientBoostingClassifier for supervised attack-family classification.

The non-IoC angle is the entire pitch. Avoid IP-blacklist features. Lean on entropy of DNS queries, beacon-timing periodicity, TLS-JA3 distribution and process-network graph divergence. Document for each detection why the IoC-based tool would have missed it.

Wrap as a Suricata or Zeek plugin that streams alerts to ELK. Demo with two attack chains — a Cobalt Strike beacon and a Mimikatz-followed-by-PsExec lateral move. Show alerting with explanation in plain English (SHAP values translated). Cite MITRE ATT&CK technique IDs in every alert.', 'AI/ML', 'advanced', 'National Technical Research Organisation', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"github.com/ahlashkari/CICFlowMeter","url":"https://github.com/ahlashkari/CICFlowMeter","kind":"repo"},{"label":"attack.mitre.org/","url":"https://attack.mitre.org/","kind":"docs"}]'::jsonb, ARRAY['network-security','behavioural-detection','mitre-attack','autoencoder','zeek']::text[]),
  ('sih-cadastral-map-ai-digitisation', 'AI-Driven Digitisation of Cadastral Maps', 'Digitise scanned cadastral maps using AI — extract parcel boundaries, khasra numbers and ownership annotations from old paper maps and produce GIS-ready vector layers tied to land-record databases.', 'Old cadastral maps are messy — faded ink, hand-written khasra numbers, partial damage. Start with the Bhoomi (Karnataka) and Apnakhata (Rajasthan) sample scans. Apply OpenCV preprocessing (CLAHE, adaptive thresholding) and then a U-Net trained to segment parcel boundaries from text and grid lines.

For the khasra number OCR, fine-tune TrOCR or PaddleOCR on Devanagari and regional digits — handwriting variation is wild, so augmentation is critical. Vectorise the segmented boundaries using Potrace and snap intersections to fix gaps.

The deliverable is a GeoPackage with parcels as polygons plus a CSV linking polygon ID to khasra. Validate by overlaying on satellite imagery — boundaries should align with field bunds. Demo with one full village map digitised end-to-end. Cite DILRMP guidelines.', 'AI/ML', 'advanced', 'Government of Jammu and Kashmir', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"dolr.gov.in/programme-schemes/dilrmp","url":"https://dolr.gov.in/programme-schemes/dilrmp","kind":"docs"},{"label":"github.com/microsoft/unilm/tree/master/trocr","url":"https://github.com/microsoft/unilm/tree/master/trocr","kind":"repo"}]'::jsonb, ARRAY['cadastral','ocr','u-net','land-records','dilrmp']::text[]),
  ('sih-tinnitus-ear-device', 'Tinnitus Frequency Matching and Adaptive Relief Device', 'Wearable device that finds a tinnitus sufferer is dominant ringing frequency through psychoacoustic matching, then plays adaptive tonal therapy and notched-music masking to provide relief over weeks of use.', 'The matching protocol is well-defined — a guided audiogram (Sandlin 1995) where the user adjusts a sine until it matches their internal tone. Build this as a 10-minute calibration routine on the device. Hardware-wise an ESP32 plus a PCM5102 DAC plus over-ear drivers works at INR 1,500.

The therapy library is two parts — pure-tone matching (Tinnitus Retraining Therapy) and notched music (Okamoto 2010 reduces audiometric notch at tinnitus frequency). Pre-process the user is uploaded music library by FFT-notching around the matched frequency.

Companion app in Flutter tracks daily use and a Tinnitus Handicap Inventory questionnaire weekly. Plot improvement over 8 weeks. Demo with a real volunteer who has measured tinnitus — testimonial beats hardware. Cite Okamoto 2010 PNAS and Jastreboff TRT throughout.', 'Health', 'advanced', 'Ministry of Social Justice and Empowerment', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"www.pnas.org/doi/10.1073/pnas.0911268107","url":"https://www.pnas.org/doi/10.1073/pnas.0911268107","kind":"paper"},{"label":"docs.espressif.com/projects/esp-idf/en/latest/esp32/api-refe","url":"https://docs.espressif.com/projects/esp-idf/en/latest/esp32/api-reference/peripherals/i2s.html","kind":"tutorial"}]'::jsonb, ARRAY['tinnitus','audiology','wearable','esp32','audiogram']::text[]),
  ('sih-vibration-motion-amplification', 'Motion Amplification Video for Vibration Analysis', 'Implement video motion amplification — make sub-pixel vibrations of machinery visible by exaggerating motion in the frequency band of interest. Used for non-contact diagnosis of bearings, blades and structures.', 'Implement the MIT Eulerian Video Magnification algorithm (Wu 2012). Decompose each frame using a Laplacian pyramid, band-pass filter the temporal signal at each spatial level (say 10-30 Hz for typical machinery), amplify by a gain factor, and reconstruct. Reference Matlab code is public; port to PyTorch with GPU.

The sweet spot for this PS is industrial — film a running pump or motor with a 240fps phone camera, point the algorithm at the housing, and visualise the bending mode. Add a spectrogram overlay so a maintenance engineer sees both visual amplification and frequency content side by side.

Delivery is a Streamlit app — upload video, pick frequency band and gain, get amplified video back. Demo with three machines — a balanced motor, an unbalanced motor and one with a cracked impeller. Cite Wu PNAS 2012 and Wadhwa Phase-Based Magnification.', 'AI/ML', 'advanced', 'Ministry of Defence', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"people.csail.mit.edu/mrub/papers/vidmag.pdf","url":"https://people.csail.mit.edu/mrub/papers/vidmag.pdf","kind":"paper"},{"label":"github.com/itberrios/CV_tracking","url":"https://github.com/itberrios/CV_tracking","kind":"repo"}]'::jsonb, ARRAY['video-magnification','vibration','eulerian','predictive-maintenance','defence']::text[]),
  ('sih-avalanche-victim-detection', 'Detection of Victims Buried Under Avalanches', 'Devise a method to locate avalanche victims buried under snow — combine RECCO-style radar, drone-borne magnetometers and thermal IR. The output is a heatmap that rescue teams use to dig in the right spot within the 15-minute survival window.', 'RECCO works at 866 MHz — buy a cheap SDR and a 866 MHz patch antenna, then build a directional finder that ranges to a passive reflector worn by skiers. For unmodified victims, combine three signals — drone-borne FLIR (warm spot under fresh snow), GPR ground-penetrating radar (penetrates 5m of snow), and a sniffer microphone for muffled cries.

Fusion is the differentiator — train a small classifier that takes all three signals and outputs a probability heatmap. Use ROS2 on a Pixhawk-based drone so missions are programmable. The heatmap renders on a tablet for the ground team.

Field trial is what wins — even a sandbox test in cold-storage with a buried mannequin and pulse oximeter proves the concept. Cite DRDO SASE Manali research and ICAR avalanche bulletins for ground truth.', 'IoT', 'advanced', 'Ministry of Defence', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"www.drdo.gov.in/labs-and-establishments/snow-avalanche-study","url":"https://www.drdo.gov.in/labs-and-establishments/snow-avalanche-study-establishment-sase","kind":"docs"},{"label":"github.com/PX4/PX4-Autopilot","url":"https://github.com/PX4/PX4-Autopilot","kind":"repo"}]'::jsonb, ARRAY['avalanche-rescue','recco','sensor-fusion','drone','thermal-ir']::text[]),
  ('sih-mental-health-tracking-children', 'Mental Health Surveillance and Tracking Among Children', 'Build a system for school-aged mental health surveillance — screen children for anxiety, depression and behavioural issues using validated instruments, track trends and route concerning cases to counsellors with consent workflows.', 'Use validated short instruments — SDQ (Strengths and Difficulties Questionnaire) and PHQ-A for adolescents. Both are open-access. Translate to Hindi/Tamil/Bengali with back-translation review. The app is two-sided — a 5-minute weekly check-in for the child (tablet at school) and a longitudinal dashboard for the school counsellor.

Consent and privacy are non-negotiable. Build parent consent flows via OTP, role-based access in Supabase, and an anonymised analytics view for the district education officer that never shows individual identities. Score the SDQ inside the app and trigger a counsellor task when scores cross the borderline threshold.

The pitch is the population view — district-level heatmap of difficulty scores, drill-down by school. Demo with a synthetic dataset of 500 students and a counsellor triage queue. Cite WHO mhGAP and Manodarpan guidelines.', 'Health', 'intermediate', 'Ministry of Education', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"www.sdqinfo.org/","url":"https://www.sdqinfo.org/","kind":"docs"},{"label":"manodarpan.education.gov.in/","url":"https://manodarpan.education.gov.in/","kind":"docs"}]'::jsonb, ARRAY['mental-health','schools','sdq','manodarpan','screening']::text[]),
  ('sih-career-counselling-ai-secondary', 'AI Career Counselling for Secondary School Students', 'Make career choice and AI-based counselling accessible to every secondary-school child via aptitude tests, interest inventories and detailed career-path roadmaps mapped to subject combinations and entrance exams.', 'Use the public RIASEC and DAT (Differential Aptitude Test) frameworks as the assessment backbone. Implement them as adaptive quizzes — early-stop using IRT (Item Response Theory) so a child does not face all 200 items. Match results to NSQF career codes which India job market actually uses.

The AI counsellor is a RAG over career profile documents — NCERT career handbook, NCS Bharat career database, and university brochures. Each career card shows subjects needed in 11-12, top three entrance exams, average starting salary and three day-in-the-life videos.

The child-facing UX matters most. Friendly avatar, gamified progress, parental email summary. Demo with three persona walk-throughs (science-oriented, arts-oriented, undecided). Cite NEP 2020 vocational integration framework.', 'Education', 'intermediate', 'Ministry of Education', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"www.ncs.gov.in/","url":"https://www.ncs.gov.in/","kind":"docs"},{"label":"www.education.gov.in/sites/upload_files/mhrd/files/NEP_Final","url":"https://www.education.gov.in/sites/upload_files/mhrd/files/NEP_Final_English_0.pdf","kind":"docs"}]'::jsonb, ARRAY['career-counselling','riasec','edtech','nep-2020','adaptive-testing']::text[]),
  ('sih-active-prosthetic-ankle', 'Active Prosthetic Ankle for Bike Riding Lower-Limb Amputees', 'Design an active prosthetic ankle that adapts for cycling and motorcycling — actuated dorsiflexion-plantarflexion under closed-loop control so a lower-limb amputee can clutch, brake and ride safely.', 'Start with an existing passive carbon-fibre foot (Jaipur Foot baseline) and add a brushless DC servo at the ankle joint with a harmonic-drive reducer. Microcontroller is a Teensy 4.1; sensing is an IMU on the shank plus a foot-plate force sensor (FSR).

The control loop must distinguish three modes — level walking, cycling (continuous rotation), motorcycle braking (rapid plantarflexion onto brake pedal). Use a state-machine plus user-controlled mode-switch on the handlebar via Bluetooth. Tune impedance per mode.

Validate on a riding rig with an able-bodied volunteer wearing it as a bypass-prosthesis. Measure clutching speed and brake force. Pitch the cost story — Indian-made at INR 80,000 vs Ottobock Empower at INR 12 lakh. Cite Herr Biomechatronics group papers.', 'Health', 'advanced', 'Ministry of Social Justice and Empowerment', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"biomech.media.mit.edu/","url":"https://biomech.media.mit.edu/","kind":"paper"},{"label":"www.pjrc.com/store/teensy41.html","url":"https://www.pjrc.com/store/teensy41.html","kind":"tutorial"}]'::jsonb, ARRAY['prosthetic','active-ankle','bldc','amputee','biomechatronics']::text[]),
  ('sih-manual-scavenging-mechanisation', 'Mechanised Solution Against Manual Sewer Cleaning', 'Engineer a mechanical or robotic alternative to manual cleaning of sewers and septic tanks — protecting sanitation workers from toxic gas exposure and physical hazard. The system must handle Indian sewer geometry and debris loads.', 'Survey the existing solutions — Bandicoot by Genrobotics is the benchmark in India; KAM, ROBI also exist. Identify a gap — most products handle straight sewers but choke on 90-degree bends. Design for that — a snake-like multi-segment robot with passive joints and a central drive shaft.

Mechanical first — a 3D-printed 4-segment chassis, off-the-shelf 24V motors, gas sensors (MQ-4 methane, MQ-7 CO) and an FPV camera. Tether for power and data. Body must fit through a 12-inch manhole. Total bill of materials under INR 75,000 so ULBs can actually procure.

Demo in a simulated sewer (PVC pipe rig with mud and rags). Record gas readings vs OSHA permissible limits to make the safety case. Cite the Prohibition of Employment as Manual Scavengers Act 2013 and recent Supreme Court directions.', 'IoT', 'advanced', 'Ministry of Social Justice and Empowerment', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"socialjustice.gov.in/writereaddata/UploadFile/MS%20Act%20201","url":"https://socialjustice.gov.in/writereaddata/UploadFile/MS%20Act%202013.pdf","kind":"docs"},{"label":"github.com/ros2","url":"https://github.com/ros2","kind":"repo"}]'::jsonb, ARRAY['sewer-robot','sanitation','gas-sensing','ros2','manual-scavenging']::text[]),
  ('sih-water-hyacinth-control', 'Control of Uncontrolled Water Hyacinth Growth in Lakes', 'Tackle the uncontrolled growth of water hyacinth (Eichhornia crassipes) in Indian lakes — through mechanical harvesting, biological control or bioconversion. The deliverable is a complete intervention plan including hardware prototype.', 'Map the problem first — Sentinel-2 NDVI on Bellandur lake (Bengaluru) or Dal Lake shows hyacinth cover as a clear high-NDVI signal over water. Build a satellite monitoring layer so you can quantify intervention impact.

For mechanical removal, design a small catamaran with a conveyor belt scoop driven by a 1HP motor. Total weight under 80kg so two people can launch from a bund. For value-add, the harvested biomass goes to biogas (proven CHnp ratio) or briquettes — cite Tamil Nadu Agricultural University pilots.

The winning angle is circular economy — show that one tonne of harvested hyacinth produces X cubic metres of biogas worth Y rupees. ULBs care about cost-recovery. Cite NMCG and ICAR-CIFRI research.', 'IoT', 'intermediate', 'Ministry of Micro Small and Medium Enterprises', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"cifri.icar.gov.in/","url":"https://cifri.icar.gov.in/","kind":"docs"},{"label":"earthengine.google.com/","url":"https://earthengine.google.com/","kind":"tutorial"}]'::jsonb, ARRAY['water-hyacinth','lake-restoration','biogas','catamaran','circular-economy']::text[]),
  ('sih-aac-indian-languages', 'Augmentative and Alternative Communication for Indian Context', 'Develop an Augmentative and Alternative Communication (AAC) device or app for non-verbal individuals — designed for Indian languages and cultural picture symbols rather than re-skinned western boards.', 'Read the ARASAAC pictogram set as a reference but build culturally appropriate alternatives — Indian food, Indian gestures, Indian relations (chacha, mausi, dada). Hire (or partner with) a special educator to validate 500 core symbols. Tile them on a Flutter app with predictive next-symbol via a small transformer.

Text-to-speech is critical — Bhashini gives Hindi, Tamil, Bengali natural voices. Add a per-user voice clone option (10-minute family member recording, processed with Coqui XTTS) so the AAC speaks in their mother is voice — a feature that lights up families.

The device target is a Raspberry Pi tablet or any Android. Demo with a real or simulated user constructing five sentences. Cite ALIMCO Kanpur and AYJNISHD AAC programs for credibility.', 'Health', 'intermediate', 'Ministry of Social Justice and Empowerment', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"arasaac.org/","url":"https://arasaac.org/","kind":"docs"},{"label":"www.bhashini.gov.in/","url":"https://www.bhashini.gov.in/","kind":"docs"}]'::jsonb, ARRAY['aac','non-verbal','accessibility','bhashini','indian-symbols']::text[]),
  ('sih-low-cost-desalination-lakshadweep', 'Low-Cost Desalination for Lakshadweep and Inland Saline Areas', 'Design a low-cost desalination technology for Lakshadweep islands and inland saline water belts — solar-driven reverse osmosis, humidification-dehumidification or membrane distillation rated for off-grid coastal villages.', 'Pick the right thermodynamic path for the feedwater. Pure seawater (35,000 ppm TDS) at Lakshadweep needs reverse osmosis — use a Dow Filmtec BW30 element rated for 2,000 ppm output. Inland brackish (3,000-10,000 ppm) is easier — membrane distillation or solar still suffices.

For an island, the constraint is power. Couple a 1 kWp solar panel to a Grundfos SQFlex pump (DC, no inverter losses) and a small pressure vessel. BOM under INR 1.5 lakh per 1,000 litre/day unit. Add a TDS sensor and a flow meter for in-field monitoring.

Build a tiny solar-still demo at lab scale (a cone of glass over a saline pool produces 4 L/m^2/day distillate). Pair with a techno-economic model in Streamlit — feed-water TDS, capex, opex, INR/litre. Pitch to NITI Aayog Lakshadweep working group; cite DRDO LRDE and NIO Goa pilots.', 'IoT', 'advanced', 'Ministry of Jal Shakti', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"nio.res.in/","url":"https://nio.res.in/","kind":"docs"},{"label":"www.sciencedirect.com/science/article/pii/S0011916415300515","url":"https://www.sciencedirect.com/science/article/pii/S0011916415300515","kind":"paper"}]'::jsonb, ARRAY['desalination','solar','reverse-osmosis','lakshadweep','brackish-water']::text[]),
  ('sih-smart-toilet-kerala', 'Smart Toilet for Hygiene and Resource Monitoring', 'Design a smart toilet that monitors hygiene (cleanliness sensors, usage counter), conserves resources (low-flow flush, water-recycling) and provides anonymised health screening via stool and urine sensors.', 'Start with the SBM hygiene specification — 10 cleanings per day at high-use locations. Instrument with a PIR for usage count, an ammonia sensor (for ureic build-up), and a moisture sensor for floor. ESP32 with WiFi for backhaul. A QR code on the door lets the user rate cleanliness (1-5) and that closes the loop with the housekeeping app.

Resource-side, fit a 3-litre dual-flush, a grey-water-recycle pump that filters wash basin water into the cistern, and a power-meter for the exhaust fan. Total retrofit cost under INR 8,000.

The health-screening layer is opt-in only — a turbidity sensor in the trap line measures gross urine colour as a hydration proxy. Do not overclaim. Pitch as a Swachh Bharat upgrade kit; cite SBM-U Mission guidelines and Bengaluru public toilet PPP data.', 'IoT', 'intermediate', 'Government of Kerala', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"swachhbharatmission.gov.in/","url":"https://swachhbharatmission.gov.in/","kind":"docs"},{"label":"randomnerdtutorials.com/projects-esp32/","url":"https://randomnerdtutorials.com/projects-esp32/","kind":"tutorial"}]'::jsonb, ARRAY['smart-toilet','swachh-bharat','esp32','hygiene','iot']::text[]),
  ('sih-fecal-decomposition-tech', 'Rapid Decomposition Technology for Fecal Sludge', 'Build a technology that rapidly decomposes fecal sludge from twin-pit toilets — biological additives, thermophilic composting or vermifiltration — so that pits can be reused safely in 6-9 months instead of 2 years.', 'Read the CSE Sanitation Capacity Building Platform manuals on twin-pit decomposition. The canonical safe interval is 24 months — your goal is to compress to 9. Three pathways exist — microbial accelerators (Bacillus and Pseudomonas), thermophilic composting (turn the pile, hit 55°C for 3 days), and vermifiltration (Eisenia fetida earthworms).

Design experiments — three identical concrete simulator pits, control + 2 treatments. Measure helminth ova reduction (NEERI protocol), volatile solids and E. coli over weeks. Even 4 weeks of preliminary data is enough for a hackathon.

Product shape — a sachet of microbial accelerator that a household drops into the inactive pit. INR 50 per sachet, six-month treatment. Pitch as a SBM scale-up product; cite CSE Sulabh and NEERI peer-reviewed work.', 'Govt', 'advanced', 'Ministry of Jal Shakti', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"www.cseindia.org/","url":"https://www.cseindia.org/","kind":"docs"},{"label":"www.who.int/water_sanitation_health/sanitation-waste/sanitat","url":"https://www.who.int/water_sanitation_health/sanitation-waste/sanitation/","kind":"paper"}]'::jsonb, ARRAY['fecal-sludge','sanitation','composting','vermifiltration','twin-pit']::text[]),
  ('sih-lowest-cost-smart-board', 'Lowest-Cost Smart Board for Seamless Teaching', 'Design the lowest-cost smart board possible — under INR 5,000 — that supports touch input, content projection and seamless integration with NCERT digital textbooks. Targets government schools without electronic infrastructure.', 'Skip the expensive interactive panel. Use a regular projector (or repurposed CRT-removed projector at INR 6,000 used) plus a Wii Remote IR tracking trick (Johnny Lee 2008) — the Wiimote tracks IR pens, mapping pen position to projected screen. Total hardware INR 4,500.

Software is OpenSankoré or your own Electron app. Pre-bundle NCERT digital textbooks (open access), DIKSHA QR-code content and a recording mode so the teacher can flip the class. Touch input via the IR pen — practice the calibration UX, it is where most attempts fail.

Demo in a real classroom is the win — bring a recorded video of grade-7 maths being taught on your INR 5,000 board, then quote the existing INR 80,000 interactive panel. Cite DIKSHA, ePathshala and Atal Tinkering Lab specs.', 'Education', 'intermediate', 'Ministry of Education', 'SIH', 'SIH 2023', 'https://www.sih.gov.in/sih2023s', '[]'::jsonb, '[{"label":"diksha.gov.in/","url":"https://diksha.gov.in/","kind":"docs"},{"label":"www.youtube.com/watch?v=5s5EvhHy7eQ","url":"https://www.youtube.com/watch?v=5s5EvhHy7eQ","kind":"tutorial"}]'::jsonb, ARRAY['smart-board','low-cost-edtech','wiimote','diksha','ncert']::text[]),
  ('sih-crime-prediction-hotspots', 'Crime Prediction Model for Mapping Hotspots', 'Build a crime prediction model that maps spatio-temporal hotspots — predicting where and when specific crime types (theft, snatching, assault) are likely to occur so that patrolling can be deployed proactively.', 'Use the public Chicago Crimes dataset (or Bengaluru police RTI-released FIR data) as a stand-in. Aggregate into a spatial grid (200m x 200m) and weekly time slots. Engineer features — past-week count, day-of-week, holiday flag, weather, distance to nearest police station, ATM density.

Model choice — start with a Poisson regression baseline, then move to a spatio-temporal GBM (LightGBM with grid+time as features) and finally an STGNN if you have GPU. The classical NIJ Real-Time Crime Forecasting Challenge methodology is your benchmark — top-N precision at the grid level.

Present as a beat-officer dashboard — heatmap for next shift overlaid on patrol routes. Add fairness checks — the model should not over-predict low-income wards. Cite the NIJ challenge and the Mohler ETAS self-exciting point process paper.', 'AI/ML', 'advanced', 'Ministry of Home Affairs', 'SIH', 'SIH 2022', 'https://sih.gov.in/sih2022event', '[{"label":"","url":"csv: https://data.cityofchicago.org"}]'::jsonb, '[{"label":"nij.ojp.gov/funding/real-time-crime-forecasting-challenge","url":"https://nij.ojp.gov/funding/real-time-crime-forecasting-challenge","kind":"paper"},{"label":"github.com/Microsoft/LightGBM","url":"https://github.com/Microsoft/LightGBM","kind":"repo"}]'::jsonb, ARRAY['crime-prediction','hotspot','stgnn','policing','nij-challenge']::text[]),
  ('gsoc-kde-kalendar-invites', 'Kalendar — Calendar Invitations with Free-Busy', 'Add iTIP/iMIP based calendar invitation flow to KDEs PIM calendar app so users can send, receive and respond to meeting invites with free-busy information. The work spans KCalendarCore, Akonadi resources and the QML front end of Kalendar.', 'Clone invent.kde.org/pim/kalendar and build it inside a kdesrc-build environment alongside kdepim-runtime. Read the existing kcalendarcore docs on api.kde.org and study how akonadi-mailfilter and the ITIP handler in kdepim-runtime already process iMIP messages from KMail.

Join the kde-pim mailing list and the #kontact:kde.org Matrix room — mentors Carl Schwan and Claudio Cambra hang out there. Reproduce the open invitation bugs filed against Kalendar on bugs.kde.org to ground a proposal in concrete UX gaps.

A strong proposal demos a small QML widget that parses an .ics attachment and writes the RSVP back to the calendar collection. Expect to touch C++ for the backend and QML for the UI.', 'OpenSource', 'intermediate', 'KDE', 'GSoC', 'GSoC 2023', 'https://community.kde.org/GSoC/2023/Ideas', '[]'::jsonb, '[{"label":"api.kde.org/kcalendarcore/html/index.html","url":"https://api.kde.org/kcalendarcore/html/index.html","kind":"docs"},{"label":"invent.kde.org/pim/kalendar","url":"https://invent.kde.org/pim/kalendar","kind":"repo"}]'::jsonb, ARRAY['c++','qml','kde','calendar','pim']::text[]),
  ('gsoc-kde-digikam-auto-tags', 'digiKam — AI-assisted Automatic Tag Assignment', 'Train a lightweight on-device classifier so digiKam can suggest meaningful tags for newly imported photographs without uploading them to a cloud service. The output integrates with the existing Faces, Items and Albums infrastructure.', 'Build digiKam from invent.kde.org/graphics/digikam — the README documents the OpenCV, exiv2 and Qt6 prerequisites. Read core/libs/dimg and core/utilities/maintenance/autotagsassignment to see how the existing FaceEngine plumbs deep-learning models into the maintenance pipeline.

Reach out to mentors Maik Qualmann and Gilles Caulier on digikam-devel@kde.org with a short proposal that picks ONE model — for example, a quantised MobileNetV3 distilled on the OpenImages dataset — and explains how it will live next to the existing FaceEngine ONNX runtime.

A convincing PoC is a CLI tool that pipes a JPEG through the chosen model and prints the top-5 labels, then a follow-up patch that wires those labels into the digikam Tags database.', 'OpenSource', 'advanced', 'KDE', 'GSoC', 'GSoC 2023', 'https://community.kde.org/GSoC/2023/Ideas', '[{"label":"storage.googleapis.com","url":"https://storage.googleapis.com/openimages/web/index.html"}]'::jsonb, '[{"label":"invent.kde.org/graphics/digikam","url":"https://invent.kde.org/graphics/digikam","kind":"repo"},{"label":"docs.kde.org/trunk5/en/digikam/digikam/index.html","url":"https://docs.kde.org/trunk5/en/digikam/digikam/index.html","kind":"docs"}]'::jsonb, ARRAY['c++','qt','opencv','onnx','computer-vision']::text[]),
  ('gsoc-osm-nominatim-category-search', 'Nominatim — Category Search via iD Editor Presets', 'Extend the OpenStreetMap geocoder so queries like hotels in Berlin or vegan restaurants near Köln resolve via the same tag presets the iD editor already curates. The work bridges the JSON preset catalogue and the Postgres-backed Nominatim query parser.', 'Clone github.com/osm-search/Nominatim and follow INSTALL.md to load a small extract — Andorra is small enough to iterate on a laptop. Then read the lib-php/SearchDescription class to see how Nominatim currently classifies special phrases.

Clone github.com/openstreetmap/iD and explore data/presets — every preset is a JSON document with terms and a key/value combo, which is exactly what category search needs. Open a discussion on github.com/osm-search/Nominatim Discussions referencing the GSoC 2023 idea before drafting a proposal.

A strong demo replaces one hard-coded special_phrases.csv row with a preset-driven equivalent and shows the same JSON test fixture still passing.', 'OpenSource', 'intermediate', 'OpenStreetMap', 'GSoC', 'GSoC 2023', 'https://wiki.openstreetmap.org/wiki/Google_Summer_of_Code/2023/Project_ideas', '[{"label":"download.geofabrik.de","url":"https://download.geofabrik.de/europe/andorra.html"}]'::jsonb, '[{"label":"github.com/osm-search/Nominatim","url":"https://github.com/osm-search/Nominatim","kind":"repo"},{"label":"github.com/openstreetmap/iD","url":"https://github.com/openstreetmap/iD","kind":"repo"}]'::jsonb, ARRAY['python','php','postgresql','osm','geocoding']::text[]),
  ('gsoc-osrm-python-bindings', 'OSRM — Native Python Bindings for the Routing Engine', 'Replace HTTP round-trips with pybind11 bindings that expose the OSRM C++ routing engine directly to Python notebooks. Targets analysts who run matrix and isochrone queries against millions of OSM nodes without paying the JSON serialisation tax.', 'Read github.com/Project-OSRM/osrm-backend/blob/master/docs/libosrm.md — the libosrm interface is the entry point you will wrap. Build osrm-backend with `cmake -B build && cmake --build build` after fetching a planet PBF or a small monaco-latest.osm.pbf for iteration.

Study how the existing Node binding in osrm-backend/src/nodejs marshals std::vector of doubles into V8 arrays — you will repeat that pattern with pybind11. Open an RFC issue on github.com/Project-OSRM/osrm-backend describing module naming (pyosrm) and target Python versions.

Demo: ship a pip-installable wheel that runs `pyosrm.Engine(path).route([lonlat, lonlat])` faster than a curl call against osrm-routed.', 'OpenSource', 'advanced', 'OpenStreetMap', 'GSoC', 'GSoC 2023', 'https://wiki.openstreetmap.org/wiki/Google_Summer_of_Code/2023/Project_ideas', '[{"label":"download.geofabrik.de","url":"https://download.geofabrik.de/europe/monaco.html"}]'::jsonb, '[{"label":"github.com/Project-OSRM/osrm-backend","url":"https://github.com/Project-OSRM/osrm-backend","kind":"repo"},{"label":"pybind11.readthedocs.io/en/stable/","url":"https://pybind11.readthedocs.io/en/stable/","kind":"docs"}]'::jsonb, ARRAY['c++','python','pybind11','routing','geo']::text[]),
  ('gsoc-valhalla-landmark-navigation', 'Valhalla — Landmark-based Turn Instructions', 'Teach the Valhalla router to emit pedestrian and cycling guidance such as turn right just after the Tesco supermarket by ranking POIs near manoeuvre nodes. The change touches the costing, narrative and tile-building stages of the pipeline.', 'Clone github.com/valhalla/valhalla and run `./scripts/dockerbuild.sh` to get a reproducible toolchain. Read docs/api/turn-by-turn/api-reference.md and src/odin/narrative_builder.cc — Odin is the module that writes manoeuvre text and where you will inject landmark hints.

Use the Geofabrik Berlin extract to rebuild tiles and join the Valhalla Slack via the link on github.com/valhalla/valhalla/blob/master/COMMUNITY.md to chat with mentors Kevin Kreiser and Nils Nolde about POI scoring.

Proof of concept: filter `amenity=*` and `shop=*` nodes within 30 m of a manoeuvre point, score them by prominence, and inject the winner into the maneuvers JSON.', 'OpenSource', 'advanced', 'OpenStreetMap', 'GSoC', 'GSoC 2023', 'https://wiki.openstreetmap.org/wiki/Google_Summer_of_Code/2023/Project_ideas', '[{"label":"download.geofabrik.de","url":"https://download.geofabrik.de/europe/germany/berlin.html"}]'::jsonb, '[{"label":"github.com/valhalla/valhalla","url":"https://github.com/valhalla/valhalla","kind":"repo"},{"label":"valhalla.github.io/valhalla/","url":"https://valhalla.github.io/valhalla/","kind":"docs"}]'::jsonb, ARRAY['c++','routing','osm','navigation','geo']::text[]),
  ('gsoc-netbsd-tickless-kernel', 'NetBSD — Tickless Kernel with High-Resolution Timers', 'Replace the periodic hz tick with an event-driven scheduler that programs the next per-CPU timer interrupt on demand. Goal: lower power draw on laptops and reduce timer overhead on busy servers.', 'Build current NetBSD from src.cvs.netbsd.org following share/doc/htdocs/guide. The relevant code lives in sys/kern/kern_clock.c, kern_timeout.c and the per-arch x86/timer.c and arm/gtmr.c. Read the dyntick papers cited in Linux Documentation/timers/no-hz.rst — many concepts map directly.

Subscribe to tech-kern@netbsd.org and announce intent before writing patches — coordinating with Christos Zoulas and Taylor R Campbell early avoids dead ends. Test changes inside `anita` (NetBSD test rig) before touching real hardware.

Progress markers: stop the clock interrupt on an idle CPU, then convert callout(9) consumers (TCP, ATA, network drivers) one at a time, validating each with the rumpkernel test suite.', 'OpenSource', 'advanced', 'NetBSD Foundation', 'GSoC', 'GSoC 2023', 'https://wiki.netbsd.org/projects/gsoc/', '[]'::jsonb, '[{"label":"www.netbsd.org/docs/kernel/","url":"https://www.netbsd.org/docs/kernel/","kind":"docs"},{"label":"github.com/NetBSD/src","url":"https://github.com/NetBSD/src","kind":"repo"}]'::jsonb, ARRAY['c','kernel','bsd','scheduling','timers']::text[]),
  ('gsoc-netbsd-ikev2-daemon', 'NetBSD — Userland IKEv2 Daemon', 'Implement an in-tree IKEv2 key-exchange daemon to replace the ageing racoon, providing modern IPsec setup that integrates with NetBSDs npf and ipsecif(4). The work covers RFC 7296 message handling and ESP SPI installation through PF_KEYv2.', 'Read RFC 7296 and survey the existing openiked and strongswan code on github.com to understand state-machine shapes. Then study NetBSDs sys/netipsec and usr.sbin/setkey to learn how SAs are pushed into the kernel.

Discuss design on tech-net@netbsd.org and tech-userlevel — mention the GSoC 2023 ideas page entry. Reuse libcrypto from OpenSSL or libnettle to avoid rolling crypto primitives.

First milestone is to negotiate IKE_SA_INIT against strongswan running in a VM, then plumb the resulting child SA into a NetBSD kernel using libpfkey.', 'OpenSource', 'advanced', 'NetBSD Foundation', 'GSoC', 'GSoC 2023', 'https://wiki.netbsd.org/projects/gsoc/', '[]'::jsonb, '[{"label":"datatracker.ietf.org/doc/html/rfc7296","url":"https://datatracker.ietf.org/doc/html/rfc7296","kind":"docs"},{"label":"github.com/NetBSD/src/tree/trunk/crypto/dist","url":"https://github.com/NetBSD/src/tree/trunk/crypto/dist","kind":"repo"}]'::jsonb, ARRAY['c','networking','ipsec','crypto','bsd']::text[]),
  ('gsoc-scummvm-game-checksum-db', 'ScummVM — Game File Integrity Verification Service', 'Build the client and server side of a checksum database so ScummVM can warn users about modified, cracked or partial game dumps and let contributors submit hashes for new variants. Implementation lives partly in the engine and partly in a Django-style web service.', 'Clone github.com/scummvm/scummvm and read engines/AGOS/detection.cpp plus common/md5.* — that is where engine identification already validates file hashes against bundled tables. Run `./configure --enable-all-engines && make` on a Linux box to build.

Join #scummvm and #scummvm-gsoc on Libera.chat — Eugene Sandulenko (sev_) led this idea in 2023. The companion website lives at scummvm.org/integritypages and integrates over HTTPS.

Milestones: extend detection so users can opt in to scanning files, define a POST /submit endpoint, then ship a UI in the launcher that flags mismatches in red.', 'OpenSource', 'intermediate', 'ScummVM', 'GSoC', 'GSoC 2023', 'https://www.scummvm.org/news/20230223/', '[]'::jsonb, '[{"label":"github.com/scummvm/scummvm","url":"https://github.com/scummvm/scummvm","kind":"repo"},{"label":"wiki.scummvm.org/index.php?title=HOWTO-Engines","url":"https://wiki.scummvm.org/index.php?title=HOWTO-Engines","kind":"docs"}]'::jsonb, ARRAY['c++','python','django','scummvm','checksum']::text[]),
  ('gsoc-scummvm-ags-color-blend', 'ScummVM — Optimising AGS Color-Blending Pipeline', 'Profile and accelerate the Adventure Game Studio engines per-pixel color blending so titles like Unavowed and Wadjet Eye games stay fluid on low-end ARM and RISC-V boards. Expected mix of SIMD, fixed-point math and cache-friendly memory layouts.', 'Read engines/ags/lib/allegro/gfx.cpp and engines/ags/engine/gfx — that is where the blend modes live. Compile ScummVM with `make GFX_DEBUG=1` and use `perf record` against a free AGS demo such as 5 Days a Stranger to find the hot loops.

The mentors hang out on #scummvm-gsoc — share flame graphs before proposing rewrites. SDL2 surface formats and ScummVMs PixelFormat APIs are critical reading.

Aim for a 30% speedup on a Raspberry Pi 4 measured by ScummVMs built-in fps counter on the same scene. Keep portable C fallbacks and gate SIMD behind autotools feature checks.', 'OpenSource', 'advanced', 'ScummVM', 'GSoC', 'GSoC 2023', 'https://www.scummvm.org/news/20230509/', '[]'::jsonb, '[{"label":"github.com/scummvm/scummvm/tree/master/engines/ags","url":"https://github.com/scummvm/scummvm/tree/master/engines/ags","kind":"repo"},{"label":"wiki.scummvm.org/index.php?title=AGS","url":"https://wiki.scummvm.org/index.php?title=AGS","kind":"docs"}]'::jsonb, ARRAY['c++','simd','gamedev','performance','scummvm']::text[]),
  ('gsoc-honeynet-mitmproxy', 'Honeynet — Mitmproxy Detection and Replay Enhancements', 'Extend mitmproxy with new contentviews, fuzzing addons and replay scripts targeted at malware analysts who use it to mediate captured C2 traffic. Output drops into the Honeynet sandbox stack alongside Cuckoo and DRAKVUF.', 'Fork github.com/mitmproxy/mitmproxy and follow CONTRIBUTING.md — pip install -e . and pytest are all you need. Read mitmproxy/addons and the new flow/http.py serialisation paths.

Introduce yourself on the Honeynet Slack #gsoc channel and look at the 2022 mitmproxy reports posted to honeynet.org/gsoc/gsoc-2022 for prior art. Mentor Maximilian Hils replies fastest on GitHub.

Deliverables: at least one new contentview for a binary protocol used by current malware (HTTP/3 QUIC stream framing is a great target) plus an addon that scriptable replays previous flows with random mutation.', 'OpenSource', 'intermediate', 'The Honeynet Project', 'GSoC', 'GSoC 2023', 'https://www.honeynet.org/gsoc/gsoc-2023/google-summer-of-code-2023-project-ideas/', '[]'::jsonb, '[{"label":"github.com/mitmproxy/mitmproxy","url":"https://github.com/mitmproxy/mitmproxy","kind":"repo"},{"label":"docs.mitmproxy.org/stable/","url":"https://docs.mitmproxy.org/stable/","kind":"docs"}]'::jsonb, ARRAY['python','security','networking','fuzzing','mitm']::text[]),
  ('gsoc-honeynet-honeyscanner', 'Honeynet — Honeyscanner Vulnerability Auditor', 'Build a brand-new scanner that fingerprints common open-source honeypots — Cowrie, Dionaea, Conpot, T-Pot — and reports their known weaknesses to defenders. Output is an attacker-style report so blue teams can patch before the bad guys notice.', 'Set up a lab with one or two Cowrie and Dionaea instances using docker-compose recipes from github.com/telekom-security/tpotce. Read existing literature on honeypot detection — search Google Scholar for honeypot fingerprinting Vetterl.

Mentor Manolis Stamatogiannakis runs the kick-off on Honeynets Slack. Start with low-hanging banner mismatches, then extend to timing side-channels and TCP fingerprinting via Nmap NSE scripts.

Final deliverable: a CLI `honeyscanner --target 10.0.0.5` that emits JSON with detected honeypot, version guess, and a CVE-style remediation hint.', 'OpenSource', 'intermediate', 'The Honeynet Project', 'GSoC', 'GSoC 2023', 'https://www.honeynet.org/gsoc/gsoc-2023/google-summer-of-code-2023-project-ideas/', '[]'::jsonb, '[{"label":"github.com/cowrie/cowrie","url":"https://github.com/cowrie/cowrie","kind":"repo"},{"label":"github.com/DinoTools/dionaea","url":"https://github.com/DinoTools/dionaea","kind":"repo"}]'::jsonb, ARRAY['python','security','honeypot','fingerprinting']::text[]),
  ('gsoc-eclipse-hara-rust-client', 'Eclipse Hara — Native Rust DDI Client for hawkBit', 'Re-implement the Direct Device Integration client that talks to Eclipse hawkBit, originally Kotlin/JVM, as a pure Rust crate using async actors. Targets industrial gateways and edge devices where the JVM footprint is too large.', 'Read github.com/eclipse/hara-ddiclient — especially api/ and the Actix-style actor wiring. Spin up a local hawkBit using the docker image on hub.docker.com/r/hawkbit/hawkbit-update-server.

Discuss design with Daniele Sergio and Diego Rondini on the Eclipse Hara mailing list before picking an actor crate — tokio plus actix or coerce-rs are both reasonable. Mirror the existing Kotlin packageContents so users can swap clients with one Cargo.toml line.

Milestone: a `hara_ddi --hawkbit-url ... --tenant default` binary that completes a full polling cycle and accepts an artifact download.', 'OpenSource', 'advanced', 'Eclipse Foundation', 'GSoC', 'GSoC 2023', 'https://wiki.eclipse.org/Google_Summer_of_Code_2023_Ideas', '[]'::jsonb, '[{"label":"github.com/eclipse/hara-ddiclient","url":"https://github.com/eclipse/hara-ddiclient","kind":"repo"},{"label":"www.eclipse.org/hawkbit/apis/ddi_api/","url":"https://www.eclipse.org/hawkbit/apis/ddi_api/","kind":"docs"}]'::jsonb, ARRAY['rust','kotlin','iot','actors','ota']::text[]),
  ('gsoc-eclipse-vertx-pinot', 'Eclipse Vert.x — Reactive Client for Apache Pinot', 'Author an idiomatic Vert.x client that talks to Apache Pinots broker REST and gRPC endpoints using non-blocking IO, async query handles and Mutiny support. Lands as a new module under vertx-clients organisation.', 'Read Vert.x core docs at vertx.io/docs/vertx-core/java/ and study existing reactive clients such as vertx-sql-client to learn naming and error handling conventions. Run Apache Pinot via docker pull apachepinot/pinot and load the airlineStats quickstart.

Mentor Thomas Segismont reviews PRs on github.com/eclipse-vertx. Discuss API shape on the vertx-dev mailing list first — bikeshedding before code is welcome.

Progress: HTTP path first using WebClient, then gRPC streaming using protoc-gen-vertx; each release ships JMH benchmarks against the official Java client.', 'OpenSource', 'intermediate', 'Eclipse Foundation', 'GSoC', 'GSoC 2023', 'https://wiki.eclipse.org/Google_Summer_of_Code_2023_Ideas', '[{"label":"docs.pinot.apache.org","url":"https://docs.pinot.apache.org/basics/getting-started/quick-start"}]'::jsonb, '[{"label":"github.com/eclipse-vertx/vert.x","url":"https://github.com/eclipse-vertx/vert.x","kind":"repo"},{"label":"docs.pinot.apache.org/","url":"https://docs.pinot.apache.org/","kind":"docs"}]'::jsonb, ARRAY['java','vertx','pinot','reactive','grpc']::text[]),
  ('gsoc-openastronomy-sunpy-helio', 'OpenAstronomy SunPy — HEK and HELIO Data Service Bridges', 'Expose the Heliophysics Events Knowledgebase and HELIO Virtual Observatory as first-class Fido search clients inside SunPy. Result: solar physicists query flares, CMEs and event catalogues with the same API used for AIA images.', 'Clone github.com/sunpy/sunpy and read sunpy/net/dataretriever — Fido clients live there. The HEK API is documented at lmsal.com/hek/api.html and uses VOEvent serialisation.

Introduce yourself on the SunPy chat at openastronomy.element.io and on the sunpy-dev mailing list. Mentors Stuart Mumford and Will Barnes review PRs on GitHub.

Deliver a `Fido.search(a.Time(...), a.helio.Service(HELIO))` invocation that returns a parsed QTable plus an example notebook reproducing a published flare catalogue.', 'OpenSource', 'intermediate', 'OpenAstronomy', 'GSoC', 'GSoC 2023', 'https://openastronomy.org/gsoc/gsoc2023/', '[{"label":"lmsal.com","url":"https://www.lmsal.com/hek/index.html"}]'::jsonb, '[{"label":"github.com/sunpy/sunpy","url":"https://github.com/sunpy/sunpy","kind":"repo"},{"label":"docs.sunpy.org/en/stable/","url":"https://docs.sunpy.org/en/stable/","kind":"docs"}]'::jsonb, ARRAY['python','astropy','sunpy','voevent','science']::text[]),
  ('gsoc-julia-graph-neural-networks', 'JuliaLang — Graph Neural Network Layers in GraphNeuralNetworks.jl', 'Add modern message-passing layers — GATv2, RGCN, PNA — to GraphNeuralNetworks.jl along with heterogeneous and temporal graph support that plays well with Flux and CUDA.jl. Target benchmark suites: OGB and TUDataset.', 'Fork github.com/CarloLucibello/GraphNeuralNetworks.jl, instantiate the project with `julia --project -e ''using Pkg; Pkg.instantiate()''` and skim test/runtests.jl to learn the conventions. The package leans on Flux for autograd and ChainRules for custom adjoints.

Join the #ml Zulip stream at julialang.zulipchat.com and the JuliaGNN Slack. Mentor Carlo Lucibello answers proposals there. Read the GATv2 paper (Brody et al. 2022) and the PNA paper (Corso et al. 2020) before writing code.

Deliverable: at least one new layer plus a benchmark notebook reproducing OGB node-prediction baselines within 1% accuracy of the published numbers.', 'OpenSource', 'advanced', 'The Julia Language', 'GSoC', 'GSoC 2023', 'https://julialang.org/jsoc/gsoc/MLJ/', '[{"label":"ogb.stanford.edu","url":"https://ogb.stanford.edu/docs/dataset_overview/"}]'::jsonb, '[{"label":"github.com/JuliaGraphs/GraphNeuralNetworks.jl","url":"https://github.com/JuliaGraphs/GraphNeuralNetworks.jl","kind":"repo"},{"label":"fluxml.ai/Flux.jl/stable/","url":"https://fluxml.ai/Flux.jl/stable/","kind":"docs"}]'::jsonb, ARRAY['julia','ml','graph','flux','gnn']::text[]),
  ('gsoc-julia-quantum-clifford', 'JuliaLang — Symbolic Optimisations in QuantumClifford.jl', 'Speed up large stabiliser-circuit simulations by adding lazy gate fusion, parallelised Tableau updates and Pauli frame propagation. Target use case is quantum-error-correction research that currently stalls on 1000-qubit codes.', 'Read github.com/QuantumSavory/QuantumClifford.jl — start with src/QuantumClifford.jl and the Tableau struct. Run benchmarks/runbenchmarks.jl to capture a baseline before optimising.

Chat with mentors Stefan Krastanov and Wojciech Kydlinski on the JuliaQuantum Slack and on Zulip #quantum. Familiarise yourself with the Heisenberg representation chapter of Nielsen & Chuang.

Final proof-of-work simulates a distance-9 surface code measurement round at least 2x faster than the current main branch, measured by BenchmarkTools.@btime.', 'OpenSource', 'advanced', 'The Julia Language', 'GSoC', 'GSoC 2023', 'https://julialang.org/jsoc/gsoc/quantum/', '[]'::jsonb, '[{"label":"github.com/QuantumSavory/QuantumClifford.jl","url":"https://github.com/QuantumSavory/QuantumClifford.jl","kind":"repo"},{"label":"qsavory.github.io/QuantumClifford.jl/stable/","url":"https://qsavory.github.io/QuantumClifford.jl/stable/","kind":"docs"}]'::jsonb, ARRAY['julia','quantum','simulation','performance']::text[]),
  ('gsoc-swift-kafka-client', 'Swift — Native Kafka Client Package', 'Wrap librdkafka with an idiomatic SwiftNIO-style producer and consumer API that uses async/await, structured concurrency and AsyncSequence so server-side Swift apps can stream events without a Java sidecar.', 'Read github.com/apple/swift-nio and github.com/swift-server/async-http-client for naming and error-handling conventions. Clone github.com/confluentinc/librdkafka and walk examples/rdkafka_example.c — every Swift method maps to a librdkafka call.

Introduce yourself on forums.swift.org under the Server category and join the #server channel on the Swift Slack. Mentors Franz Busch and Konrad Malawski review proposals there.

Milestones: a SwiftPM module that ships precompiled librdkafka on Linux and macOS, a Producer.send(record:) demo and an integration test running against a docker-compose Kafka cluster.', 'OpenSource', 'advanced', 'Swift', 'GSoC', 'GSoC 2022', 'https://www.swift.org/gsoc2022/', '[]'::jsonb, '[{"label":"github.com/confluentinc/librdkafka","url":"https://github.com/confluentinc/librdkafka","kind":"repo"},{"label":"www.swift.org/server/","url":"https://www.swift.org/server/","kind":"docs"}]'::jsonb, ARRAY['swift','kafka','concurrency','server','c-interop']::text[]),
  ('gsoc-swift-linux-backtraces', 'Swift on Linux — Quality Backtraces on Crash', 'Add a built-in crash reporter that prints symbolicated, demangled Swift backtraces on Linux when a process aborts — matching the experience already available on macOS. Touches the Swift runtime, the toolchain and how DWARF is shipped in tarballs.', 'Clone github.com/apple/swift and read stdlib/public/runtime/Backtrace.cpp plus the existing macOS implementation under stdlib/public/runtime/CrashReporter.cpp. Build the toolchain with `utils/build-script --release-debuginfo`.

Discuss on forums.swift.org under Development > Compiler. Mentor Alastair Houghton (alastairh) drove this idea in 2022. Survey libunwind, libbacktrace and Linux DWARF unwind sections so your proposal picks one stack walker.

Deliverable: when a Swift binary built with `-g` crashes on Linux, stderr contains a demangled backtrace ending at main() with file:line for each frame.', 'OpenSource', 'advanced', 'Swift', 'GSoC', 'GSoC 2022', 'https://www.swift.org/gsoc2022/', '[]'::jsonb, '[{"label":"github.com/apple/swift","url":"https://github.com/apple/swift","kind":"repo"},{"label":"github.com/apple/swift/blob/main/docs/index.md","url":"https://github.com/apple/swift/blob/main/docs/index.md","kind":"docs"}]'::jsonb, ARRAY['swift','c++','linux','runtime','debugging']::text[]),
  ('gsoc-plone-webauthn', 'Plone — Passwordless WebAuthn 2 Authentication', 'Add WebAuthn level 2 support to the Plone CMS so users can authenticate with hardware tokens (YubiKey, Touch ID, Windows Hello) instead of passwords. The work spans the PAS plugin layer in Python and the React-based Volto front-end.', 'Stand up a Plone 6 site via cookiecutter-plone-starter and confirm you can swap PAS plugins by reading docs.plone.org/develop/plone/security/pas.html. The companion w3c spec lives at www.w3.org/TR/webauthn-2/.

Reach out to Andreas Jung (zopyx) on the Plone community Discord and on community.plone.org. Reuse python-fido2 from Yubico to avoid implementing CBOR and attestation from scratch.

Final demo: register a YubiKey from the Volto user-profile view, then sign in on a second browser session using only the key, including recovery and backup flows.', 'OpenSource', 'advanced', 'Plone', 'GSoC', 'GSoC 2023', 'https://plone.org/community/gsoc/2023', '[]'::jsonb, '[{"label":"www.w3.org/TR/webauthn-2/","url":"https://www.w3.org/TR/webauthn-2/","kind":"docs"},{"label":"github.com/Yubico/python-fido2","url":"https://github.com/Yubico/python-fido2","kind":"repo"}]'::jsonb, ARRAY['python','react','webauthn','fido2','cms']::text[]),
  ('gsoc-plone-blocks-dnd-kit', 'Plone Volto — Drag-and-Drop Refactor on dnd-kit', 'Replace the ageing react-dnd implementation in Voltos Blocks engine with the modern dnd-kit library so content editors get accessible keyboard reordering and cross-container drags between nested layouts.', 'Clone github.com/plone/volto and read packages/volto/src/components/manage/Blocks. The existing DnD plumbing lives in BlocksForm.jsx and Block/Edit.jsx. Read dndkit.com/docs to learn DroppableContext and modifiers.

Mentor Víctor Fernández de Alba (sneridagh) holds office hours on the Plone Discord. Pair a proposal with a small CodeSandbox prototype that already shows nested drag works.

Deliverable: drag a Slate text block between two grid columns using a keyboard alone, with full a11y announcements and undo/redo working in Volto.', 'OpenSource', 'intermediate', 'Plone', 'GSoC', 'GSoC 2023', 'https://plone.org/community/gsoc/2023', '[]'::jsonb, '[{"label":"github.com/plone/volto","url":"https://github.com/plone/volto","kind":"repo"},{"label":"docs.dndkit.com/","url":"https://docs.dndkit.com/","kind":"docs"}]'::jsonb, ARRAY['javascript','react','cms','a11y','dnd']::text[]),
  ('gsoc-gnome-bustle-rust', 'GNOME — Rewrite Bustle in Rust + GTK 4', 'Port the D-Bus message visualiser Bustle from Haskell + GTK 3 to Rust + GTK 4, picking up zbus as the message library. Output is a modern flatpaked app that GNOME developers can ship from Flathub.', 'Fork gitlab.gnome.org/World/bustle and the upstream gitlab.freedesktop.org/bustle/bustle. Read the .ui XML files plus the Haskell renderer — the timeline drawing is the trickiest part. Familiarise yourself with relm4 or the official gtk-rs crates.

